    if (pos>0) {
      key=substr($0,1,pos-1); val=substr($0,pos+1)
      full=sec SUBSEP key
      if (!(full in key_seen)) { key_seen[full]=1; key_order[sec,++key_count[sec]]=key }
      value[full]=val
    }
    next
  }
  file==2 {
    if ($0 ~ /^\[[^]]+\]$/) {
      sec=substr($0,2,length($0)-2)
      if (!(sec in sec_seen)) { sec_seen[sec]=1; sec_order[++nsec]=sec }
      next
    }
    if ($0 ~ /^[[:space:]]*$/) next
    pos=index($0,"=")
    if (pos>0) {
      key=substr($0,1,pos-1); val=substr($0,pos+1)
      full=sec SUBSEP key
      if (!(full in key_seen)) { key_seen[full]=1; key_order[sec,++key_count[sec]]=key }
      value[full]=val
    }
  }
  END {
    for (i=1; i<=nsec; i++) {
      sec=sec_order[i]
      print "[" sec "]"
      for (j=1; j<=key_count[sec]; j++) {
        key=key_order[sec,j]
        print key "=" value[sec SUBSEP key]
      }
      if (i<nsec) print ""
    }
  }
' /config/defaults.ini /config/custom.ini > /config/merged.ini
